VALUES
  ('judicial-cf446b4c-moex-00144', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'essay', '甲因個人因素，不便登記為 A屋之所有權人，遂與好友乙約定，將 A屋
登記在乙之名下，但由甲自己使用居住。好友乙因車禍意外死亡，當時
甲因工作旅居義大利，乙的繼承人丙繼承 A屋後，將 A屋賣給不知情的
丁，並將 A屋移轉登記給丁。俟甲回國後，發現丁正在整理 A屋，甲對
丁主張自己是 A屋所有權人，丁則對甲主張自己才是 A屋所有權人，故
請甲清理留置於A屋之物品。請問誰的主張有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00145', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '因侵權行為所生之損害賠償請求權，自請求權人知有損害及賠償義務人時起，幾年間不行使而消 滅？自有侵權行為時起，逾幾年者亦同？ 分別為1年與5年    分別為2年與10年 分別為3年與15年   分別為5年與15年', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00146', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於消滅時效之敘述，何者正確？ 消滅時效經請求而中斷，所以債權人對於債務人只要不斷請求履行債務，即可達到債權請求權 之時效永遠不完成 消滅時效因起訴而中斷，但若撤回其訴訟，時效視為不中斷 消滅時效經聲請調解而中斷，但若雙方當事人調解不成立，則消滅時效之計算自不成立時，重 新起算 關於無行為能力人對於法定代理人之權利之消滅時效計算，不受法定代理人之代理關係影響', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00147', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '定期贍養費之請求權消滅時效期間為何？ 1年  2年  5年  15年', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00148', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲對乙之侵權行為損害賠償請求權，已於上個月罹於消滅時效。下列敘述，何者正確？ 甲之請求權已經消滅 乙於賠償後，得以不知時效為理由請求返還 乙得拒絕賠償 甲得現在起訴乙，以中斷消滅時效', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00149', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列何者非屬身分行為？ 甲乙結婚之行為 父親甲贈與其子乙新臺幣200萬元，供其支付購屋頭期款之贈與行為 甲乙結婚，共同訂立夫妻財產契約 法定繼承人拋棄繼承之行為', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00150', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '依民法第92條第1項規定，被詐欺而為意思表示，表意人得撤銷其意思表示。關於此撤銷權，下 列敘述，何者錯誤？ 屬於形成權    該意思表示經撤銷後，視為自始無效 適用一年之消滅時效期間  其撤銷不得對抗善意第三人', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00151', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '於符合得行使下列各種權利要件時，何者非屬由一方當事人向相對人為意思表示即生效力之情 形？ 表示行使解除權之意思  表示免除債務之意思 表示主張抵銷之意思  表示行使債權人撤銷權之意思', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00152', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲向乙承租其所有之A屋。依民法規定，下列敘述，何者錯誤？ 若乙不同意，甲不得將A屋全部轉租第三人丙 若甲乙雙方無反對之約定，甲得將A屋一部分轉租第三人丙 若甲將A屋違法轉租第三人丙，甲丙間之租賃契約仍為有效 若甲將A屋合法轉租第三人丙，則因丙應負責任之事由所生之損害，甲不負賠償責任', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00153', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲住於A地，與住於B地之乙，於C地締結甲所有並保管於D地之X名畫買賣契約，但二人疏 未約定交付該畫之地點。清償期屆至時，甲應於何地交付該畫於乙？ A地  B地  C地  D地', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
